import sqlite3

def get_order(user_id, order_id):
    conn = sqlite3.connect('orders.db')
    c = conn.cursor()

    c.execute('''SELECT * FROM orders WHERE user_id=? AND order_id=?''', (user_id, order_id))
    result = c.fetchone()

    if result:
        order = {key[0]: value for key, value in zip(c.description, result)}
        return order
    else:
        return None

